import{_ as t,c as a,o as d,aT as i}from"./chunks/framework.qpm8FIA8.js";const m=JSON.parse('{"title":"Git 基本操作","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/git/git-basic-operations.md","filePath":"frontend/git/git-basic-operations.md","lastUpdated":1711621612000}'),e={name:"frontend/git/git-basic-operations.md"},r=i(`<h1 id="git-基本操作" tabindex="-1">Git 基本操作 <a class="header-anchor" href="#git-基本操作" aria-label="Permalink to &quot;Git 基本操作&quot;">​</a></h1><p>Git 的工作就是创建和保存你项目的快照及与之后的快照进行对比。</p><p>本章将对有关创建与提交你的项目快照的命令作介绍。</p><p>Git 常用的是以下 6 个命令：git clone、git push、git add 、git commit、git checkout、git pull，后面我们会详细介绍。</p><p><img src="https://www.runoob.com/wp-content/uploads/2015/02/git-command.jpg" alt="https://www.runoob.com/wp-content/uploads/2015/02/git-command.jpg" loading="lazy"></p><p><strong>说明：</strong></p><ul><li><p>workspace：工作区</p></li><li><p>staging area：暂存区/缓存区</p></li><li><p>local repository：版本库或本地仓库</p></li><li><p>remote repository：远程仓库</p></li></ul><p>一个简单的操作步骤：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>$ git init    </span></span>
<span class="line"><span>$ git add .    </span></span>
<span class="line"><span>$ git commit</span></span></code></pre></div><ul><li>git init - 初始化仓库。</li><li>git add . - 添加文件到暂存区。</li><li>git commit - 将暂存区内容添加到仓库中。</li></ul><h2 id="创建仓库命令" tabindex="-1">创建仓库命令 <a class="header-anchor" href="#创建仓库命令" aria-label="Permalink to &quot;创建仓库命令&quot;">​</a></h2><p>下表列出了 git 创建仓库的命令：</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>git init</td><td>初始化仓库</td></tr><tr><td>git clone</td><td>拷贝一份远程仓库，也就是下载一个项目</td></tr></tbody></table><h2 id="提交与修改" tabindex="-1">提交与修改 <a class="header-anchor" href="#提交与修改" aria-label="Permalink to &quot;提交与修改&quot;">​</a></h2><p>Git 的工作就是创建和保存你的项目的快照及与之后的快照进行对比。</p><p>下表列出了有关创建与提交你的项目的快照的命令：</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>git add</td><td>添加文件到暂存区</td></tr><tr><td>git status</td><td>查看仓库当前的状态，显示有变更的文件。</td></tr><tr><td>git diff</td><td>比较文件的不同，即暂存区和工作区的差异。</td></tr><tr><td>git commit</td><td>提交暂存区到本地仓库。</td></tr><tr><td>git reset</td><td>回退版本。</td></tr><tr><td>git rm</td><td>将文件从暂存区和工作区中删除。</td></tr><tr><td>git mv</td><td>移动或重命名工作区文件。</td></tr><tr><td>git checkout</td><td>分支切换。</td></tr><tr><td>git switch （Git 2.23 版本引入）</td><td>更清晰地切换分支。</td></tr><tr><td>git restore （Git 2.23 版本引入）</td><td>恢复或撤销文件的更改。</td></tr></tbody></table><h2 id="提交日志" tabindex="-1">提交日志 <a class="header-anchor" href="#提交日志" aria-label="Permalink to &quot;提交日志&quot;">​</a></h2><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>git log</td><td>查看历史提交记录</td></tr><tr><td>git blame file</td><td>以列表形式查看指定文件的历史修改记录</td></tr></tbody></table><h2 id="远程操作" tabindex="-1">远程操作 <a class="header-anchor" href="#远程操作" aria-label="Permalink to &quot;远程操作&quot;">​</a></h2><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>git remote</td><td>远程仓库操作</td></tr><tr><td>git fetch</td><td>从远程获取代码库</td></tr><tr><td>git pull</td><td>下载远程代码并合并</td></tr><tr><td>git push</td><td>上传远程代码并合并</td></tr></tbody></table>`,21),o=[r];function s(l,n,p,h,c,g){return d(),a("div",null,o)}const u=t(e,[["render",s]]);export{m as __pageData,u as default};
